import React from 'react';
import { Pressable, SafeAreaView, ScrollView, StyleSheet, Text, View } from 'react-native';
import CustomerBottomNav from '../components/CustomerBottomNav';
import { createShadow } from '../styles/shadows';

const balance = 40;
const rechargeOptions = ['Rs100', 'Rs200', 'Rs500', 'Rs1000'];

const transactions = [
  { id: 'tx1', title: 'Wallet Recharge', type: 'credit', date: '14 Apr 2026', amount: '+ Rs500', status: 'Success' },
  { id: 'tx2', title: 'Order Payment', type: 'debit', date: '13 Apr 2026', amount: '- Rs120', status: 'Paid' },
  { id: 'tx3', title: 'Wallet Recharge', type: 'credit', date: '11 Apr 2026', amount: '+ Rs200', status: 'Success' },
  { id: 'tx4', title: 'Order Payment', type: 'debit', date: '10 Apr 2026', amount: '- Rs40', status: 'Pending' }
];

const paymentMethods = [
  { id: 'pm1', title: 'UPI', subtitle: 'Fast recharge with any UPI app', icon: 'U' },
  { id: 'pm2', title: 'Card', subtitle: 'Credit or debit card payment', icon: 'C' },
  { id: 'pm3', title: 'Net Banking', subtitle: 'Direct payment from your bank', icon: 'N' }
];

const statusTone = (status: string) => {
  switch (status) {
    case 'Success':
    case 'Paid':
      return { badge: styles.statusSuccess, text: styles.statusTextSuccess };
    case 'Pending':
      return { badge: styles.statusPending, text: styles.statusTextPending };
    default:
      return { badge: styles.statusNeutral, text: styles.statusTextNeutral };
  }
};

const CustomerWalletScreen = () => {
  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
        <View style={styles.header}>
          <Text style={styles.eyebrow}>Wallet</Text>
          <Text style={styles.title}>Simple wallet for faster payments</Text>
          <Text style={styles.subtitle}>Recharge quickly, pay for orders from balance, and track every wallet movement.</Text>
        </View>

        <View style={styles.balanceCard}>
          <View style={styles.balanceTopRow}>
            <View>
              <Text style={styles.balanceLabel}>Current wallet balance</Text>
              <Text style={styles.balanceValue}>Rs {balance}</Text>
            </View>
            <View style={styles.balancePill}>
              <Text style={styles.balancePillText}>Ready to use</Text>
            </View>
          </View>
          <Text style={styles.balanceHint}>Use wallet balance for quick payments during order confirmation.</Text>
        </View>

        {balance < 50 ? (
          <View style={styles.warningCard}>
            <Text style={styles.warningTitle}>Low balance</Text>
            <Text style={styles.warningText}>Your wallet balance is below Rs 50. Add money before placing the next order.</Text>
          </View>
        ) : null}

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>Add money</Text>
          <Text style={styles.sectionSubtitle}>Choose a quick recharge amount</Text>
          <View style={styles.rechargeGrid}>
            {rechargeOptions.map((amount) => (
              <Pressable key={amount} style={styles.amountChip}>
                <Text style={styles.amountChipText}>{amount}</Text>
              </Pressable>
            ))}
          </View>
          <Pressable style={styles.primaryButton}>
            <Text style={styles.primaryButtonText}>Add Money</Text>
          </Pressable>
        </View>

        <View style={styles.card}>
          <Text style={styles.sectionTitle}>Pay for order</Text>
          <Text style={styles.sectionSubtitle}>Use available wallet balance for the next delivery payment</Text>
          <View style={styles.payCard}>
            <View>
              <Text style={styles.payLabel}>Available to spend</Text>
              <Text style={styles.payValue}>Rs {balance}</Text>
            </View>
            <Pressable style={styles.secondaryButton}>
              <Text style={styles.secondaryButtonText}>Pay for Order</Text>
            </Pressable>
          </View>
        </View>

        <View style={styles.card}>
          <View style={styles.sectionHeader}>
            <Text style={styles.sectionTitle}>Transaction history</Text>
            <Text style={styles.sectionMeta}>Credit and debit</Text>
          </View>
          {transactions.map((transaction) => {
            const tone = statusTone(transaction.status);
            const isCredit = transaction.type === 'credit';

            return (
              <View key={transaction.id} style={styles.transactionRow}>
                <View style={[styles.transactionIcon, isCredit ? styles.creditIcon : styles.debitIcon]}>
                  <Text style={[styles.transactionIconText, isCredit ? styles.creditIconText : styles.debitIconText]}>
                    {isCredit ? '+' : '-'}
                  </Text>
                </View>
                <View style={styles.transactionBody}>
                  <Text style={styles.transactionTitle}>{transaction.title}</Text>
                  <Text style={styles.transactionDate}>{transaction.date}</Text>
                </View>
                <View style={styles.transactionRight}>
                  <Text style={styles.transactionAmount}>{transaction.amount}</Text>
                  <View style={[styles.statusBadge, tone.badge]}>
                    <Text style={[styles.statusText, tone.text]}>{transaction.status}</Text>
                  </View>
                </View>
              </View>
            );
          })}
        </View>

        <View style={styles.card}>
          <View style={styles.sectionHeader}>
            <Text style={styles.sectionTitle}>Payment methods</Text>
            <Text style={styles.sectionMeta}>Recharge options</Text>
          </View>
          {paymentMethods.map((method) => (
            <View key={method.id} style={styles.methodRow}>
              <View style={styles.methodIcon}>
                <Text style={styles.methodIconText}>{method.icon}</Text>
              </View>
              <View style={styles.methodBody}>
                <Text style={styles.methodTitle}>{method.title}</Text>
                <Text style={styles.methodSubtitle}>{method.subtitle}</Text>
              </View>
            </View>
          ))}
        </View>
      </ScrollView>
      <CustomerBottomNav active="CustomerWallet" />
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F4F8FC',
    position: 'relative',
    height: '100%'
  },
  content: {
    paddingHorizontal: 18,
    paddingTop: 20,
    paddingBottom: 108
  },
  header: {
    marginBottom: 18
  },
  eyebrow: {
    color: '#68859B',
    fontSize: 12,
    fontWeight: '800',
    textTransform: 'uppercase',
    letterSpacing: 1
  },
  title: {
    marginTop: 6,
    color: '#11263D',
    fontSize: 28,
    fontWeight: '900'
  },
  subtitle: {
    marginTop: 8,
    color: '#5E7486',
    fontSize: 14,
    lineHeight: 21
  },
  balanceCard: {
    backgroundColor: '#DDF1FF',
    borderRadius: 28,
    padding: 20,
    borderWidth: 1,
    borderColor: '#C7E4FA',
    marginBottom: 14
  },
  balanceTopRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'flex-start'
  },
  balanceLabel: {
    color: '#4D6D84',
    fontSize: 13,
    fontWeight: '700'
  },
  balanceValue: {
    marginTop: 8,
    color: '#11263D',
    fontSize: 34,
    fontWeight: '900'
  },
  balancePill: {
    backgroundColor: 'rgba(255,255,255,0.82)',
    borderRadius: 999,
    paddingHorizontal: 12,
    paddingVertical: 7
  },
  balancePillText: {
    color: '#0D6AA8',
    fontSize: 11,
    fontWeight: '800'
  },
  balanceHint: {
    marginTop: 14,
    color: '#4C6C84',
    fontSize: 13,
    lineHeight: 20
  },
  warningCard: {
    backgroundColor: '#FFF4D6',
    borderRadius: 20,
    padding: 16,
    borderWidth: 1,
    borderColor: '#F8D98A',
    marginBottom: 14
  },
  warningTitle: {
    color: '#9A5B00',
    fontSize: 14,
    fontWeight: '800'
  },
  warningText: {
    marginTop: 6,
    color: '#9A5B00',
    fontSize: 13,
    lineHeight: 19
  },
  card: {
    backgroundColor: 'white',
    borderRadius: 24,
    padding: 18,
    marginBottom: 14,
    ...createShadow({ color: '#123A58', opacity: 0.05, radius: 14, elevation: 4 })
  },
  sectionHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 12
  },
  sectionTitle: {
    color: '#11263D',
    fontSize: 18,
    fontWeight: '800'
  },
  sectionSubtitle: {
    marginTop: 4,
    color: '#75899B',
    fontSize: 12,
    lineHeight: 18
  },
  sectionMeta: {
    color: '#7D93A5',
    fontSize: 11,
    fontWeight: '700',
    textTransform: 'uppercase',
    letterSpacing: 0.8
  },
  rechargeGrid: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: 10,
    marginTop: 14
  },
